    WriteRegisterWord(RegisterType::PC, 0x8A16);
    WriteRegisterWord(RegisterType::SP, 0x4FAB);
    WriteRegisterByte(RegisterType::A, 0x0B);
    WriteRegisterByte(RegisterType::B, 0x00);
